// ─────────────────────────────────────────────
// Scoring ICP (Ideal Customer Profile)
// Adaptez les seuils et mots-clés à votre cible.
// ─────────────────────────────────────────────

const TAILLE_MIN = 20;              // employés minimum
const SENIORITE_CIBLE = ['executive', 'director', 'vp', 'manager', 'senior'];
const MOTS_CLES_POSTE = ['ceo', 'cto', 'cmo', 'cfo', 'founder', 'head', 'director', 'directeur', 'responsable', 'manager', 'lead'];

const out = [];

for (const item of $input.all()) {
  const form = item.json;
  const data = (form.data) || {};        // réponse Hunter (combined/find)
  const person = data.person || {};
  const company = data.company || {};
  const employment = person.employment || {};

  // Champs normalisés (avec repli sur les colonnes du formulaire)
  const email = data.email || form.Email || form['Adresse e-mail'] || form['Email Address'] || '';
  const fullName = (person.name && person.name.fullName)
    || [form.Prénom, form.Nom].filter(Boolean).join(' ')
    || form['Nom complet'] || email.split('@')[0];
  const companyName = company.name || (employment && employment.name) || '';
  const employees = (company.metrics && company.metrics.employees) || 0;
  const title = employment.title || form.Poste || '';
  const seniority = (employment.seniority || '').toLowerCase();
  const industry = (company.category && company.category.industry) || '';

  // ── Critères de qualification ──
  const tailleOk = employees >= TAILLE_MIN;
  const senioriteOk = SENIORITE_CIBLE.includes(seniority);
  const posteOk = MOTS_CLES_POSTE.some(k => title.toLowerCase().includes(k));
  const aEntreprise = companyName.length > 0;

  // Score simple (0–4)
  let score = 0;
  if (tailleOk) score++;
  if (senioriteOk) score++;
  if (posteOk) score++;
  if (aEntreprise) score++;

  // Qualifié si entreprise identifiée ET (décideur OU bonne taille)
  const qualified = aEntreprise && (senioriteOk || posteOk || tailleOk);

  out.push({
    json: {
      email,
      fullName,
      companyName,
      employees,
      title,
      seniority,
      industry,
      score,
      qualified,
      raisonsScore: { tailleOk, senioriteOk, posteOk, aEntreprise }
    }
  });
}

return out;
